    \item \pin{57}{SLP\_S3\#} - Sleep state indicator (S3 = Suspend to RAM)
    \item \pin{52}{SLP\_S4\#} - Sleep state indicator (S4 = Hibernate)
    \item \pin{86}{ADP\_PRES\_OUT} - Adapter presence detection
    \item \pin{1}{VCC1\_POR\#\_3} - Power-on reset
\end{itemize}

\begin{figure}[H]
\centering
\includegraphics[width=0.85\linewidth]{output/page46_full.png}
